param(
  [string]$Prefix = $(if ($env:GNOSIS_INSTALL_PREFIX) { $env:GNOSIS_INSTALL_PREFIX } else { Join-Path $HOME ".gnosis" }),
  [string]$ArtifactUrl = $env:GNOSIS_ARTIFACT_URL,
  [string]$ArtifactDir = $env:GNOSIS_ARTIFACT_DIR,
  [switch]$FromSource,
  [switch]$WithMoonshine,
  [switch]$NoPath,
  [switch]$DryRun,
  [switch]$Force,
  [switch]$Help
)

$ErrorActionPreference = "Stop"
$ScriptDir = Split-Path -Parent $MyInvocation.MyCommand.Path
$GnosisRoot = $ScriptDir
$BinDir = Join-Path $Prefix "bin"
$LibDir = Join-Path (Join-Path $Prefix "lib") "gnosis"
$CommandRoot = $LibDir

function Show-Usage {
  @"
Usage: .\install.ps1 [options]

Installs user-facing Gnosis commands without the monorepo developer setup.

Options:
  -Prefix <dir>          Install prefix (default: `$HOME\.gnosis)
  -ArtifactUrl <url>     Download and install a release bundle
  -ArtifactDir <dir>     Install from an unpacked release bundle
  -FromSource            Build native binaries from this checkout when possible
  -WithMoonshine         Also install moonshine
  -NoPath                Do not update the user PATH
  -DryRun                Print actions without writing
  -Force                 Replace existing installed package tree
  -Help                  Show this help

Release bundles may contain either:
  gnosis\                package tree used by the command wrappers
  bin\monster.exe        native monster binary
  bin\gnexec.exe         native gnexec binary
  bin\moonshine.exe      optional moonshine binary
  gnosis-install-manifest.json
"@
}

if ($Help) {
  Show-Usage
  exit 0
}

function Invoke-Step {
  param(
    [string]$Description,
    [scriptblock]$Action
  )
  if ($DryRun) {
    Write-Host "[dry-run] $Description"
  } else {
    & $Action
  }
}

function Get-HostTarget {
  $os = "windows"
  $arch = if ([System.Runtime.InteropServices.RuntimeInformation]::OSArchitecture -eq [System.Runtime.InteropServices.Architecture]::Arm64) { "arm64" } else { "x64" }
  "$os-$arch"
}

function Copy-Tree {
  param([string]$Source, [string]$Destination)
  if (!(Test-Path -LiteralPath $Source -PathType Container)) {
    throw "source tree not found: $Source"
  }
  if ((Test-Path -LiteralPath $Destination) -and !$Force) {
    throw "$Destination already exists; use -Force to replace it"
  }
  Invoke-Step "remove $Destination" { Remove-Item -LiteralPath $Destination -Recurse -Force -ErrorAction SilentlyContinue }
  Invoke-Step "create $(Split-Path -Parent $Destination)" { New-Item -ItemType Directory -Force -Path (Split-Path -Parent $Destination) | Out-Null }
  Invoke-Step "copy $Source to $Destination" {
    New-Item -ItemType Directory -Force -Path $Destination | Out-Null
    Get-ChildItem -LiteralPath $Source -Force | Where-Object {
      $_.Name -notin @("node_modules", "target", ".git", ".lake")
    } | ForEach-Object {
      Copy-Item -LiteralPath $_.FullName -Destination $Destination -Recurse -Force
    }
  }
}

function Expand-Artifact {
  if (!$ArtifactUrl) {
    return $ArtifactDir
  }
  $tmp = Join-Path ([System.IO.Path]::GetTempPath()) "gnosis-install-$PID"
  $archive = Join-Path $tmp "artifact"
  Invoke-Step "create $tmp" { New-Item -ItemType Directory -Force -Path $tmp | Out-Null }
  Invoke-Step "download $ArtifactUrl" { Invoke-WebRequest -Uri $ArtifactUrl -OutFile $archive }
  $unpacked = Join-Path $tmp "unpacked"
  Invoke-Step "create $unpacked" { New-Item -ItemType Directory -Force -Path $unpacked | Out-Null }
  if ($ArtifactUrl.EndsWith(".zip")) {
    Invoke-Step "expand zip artifact" { Expand-Archive -LiteralPath $archive -DestinationPath $unpacked -Force }
  } elseif ($ArtifactUrl.EndsWith(".tar.gz") -or $ArtifactUrl.EndsWith(".tgz")) {
    Invoke-Step "expand tar artifact" { tar -xzf $archive -C $unpacked }
  } else {
    throw "artifact URL must end in .tar.gz, .tgz, or .zip"
  }
  $unpacked
}

function Install-FromArtifactDir {
  param([string]$Dir)
  if (!$Dir) {
    return $false
  }
  if (!(Test-Path -LiteralPath $Dir -PathType Container)) {
    throw "artifact directory not found: $Dir"
  }
  $targetDir = Join-Path $Dir (Get-HostTarget)
  if (Test-Path -LiteralPath $targetDir -PathType Container) {
    $Dir = $targetDir
  }
  $artifactPackage = Join-Path $Dir "gnosis"
  if (!(Test-Path -LiteralPath $artifactPackage -PathType Container)) {
    throw "artifact bundle must contain a gnosis\ package tree"
  }
  Copy-Tree $artifactPackage $LibDir
  $nativeDir = Join-Path (Join-Path (Join-Path $LibDir "polyglot") "target") "release"
  Invoke-Step "create $nativeDir" { New-Item -ItemType Directory -Force -Path $nativeDir | Out-Null }
  foreach ($name in @("monster", "gnexec")) {
    $source = Join-Path (Join-Path $Dir "bin") "$name.exe"
    if (Test-Path -LiteralPath $source -PathType Leaf) {
      Invoke-Step "copy $source" { Copy-Item -LiteralPath $source -Destination (Join-Path $nativeDir "$name.exe") -Force }
    }
  }
  if ($WithMoonshine) {
    $source = Join-Path (Join-Path $Dir "bin") "moonshine.exe"
    if (Test-Path -LiteralPath $source -PathType Leaf) {
      $moonDir = Join-Path (Join-Path (Join-Path $LibDir "moonshine") "target") "release"
      Invoke-Step "create $moonDir" { New-Item -ItemType Directory -Force -Path $moonDir | Out-Null }
      Invoke-Step "copy $source" { Copy-Item -LiteralPath $source -Destination (Join-Path $moonDir "moonshine.exe") -Force }
    }
  }
  $true
}

function Install-FromCheckout {
  if (!(Test-Path -LiteralPath (Join-Path $GnosisRoot "bin\gnode.js") -PathType Leaf)) {
    throw "this script must run from an open-source/gnosis checkout or release bundle"
  }
  $script:CommandRoot = $GnosisRoot
  Invoke-Step "create $(Split-Path -Parent $LibDir)" { New-Item -ItemType Directory -Force -Path (Split-Path -Parent $LibDir) | Out-Null }
  Write-Host "Using checkout package tree: $GnosisRoot"
}

function Test-CheckoutCanBuildNative {
  (Test-Path -LiteralPath (Join-Path $GnosisRoot "polyglot\Cargo.toml") -PathType Leaf) -and
    (Test-Path -LiteralPath (Join-Path $GnosisRoot "..\..\gnot") -PathType Container)
}

function Build-NativeFromSource {
  if (!$FromSource) {
    return
  }
  if (!(Get-Command cargo -ErrorAction SilentlyContinue)) {
    throw "-FromSource requires cargo"
  }
  if (!(Test-CheckoutCanBuildNative)) {
    throw "isolated open-source/gnosis checkouts cannot build native monster/gnexec; use a release artifact"
  }
  Invoke-Step "cargo build monster and gnexec" {
    cargo build --manifest-path (Join-Path $GnosisRoot "polyglot\Cargo.toml") --bin monster --bin gnexec --release --target-dir (Join-Path $GnosisRoot "polyglot\target")
  }
}

function Build-MoonshineFromSource {
  if (!$WithMoonshine) {
    return
  }
  $installed = Join-Path (Join-Path (Join-Path $LibDir "moonshine") "target\release") "moonshine.exe"
  if (Test-Path -LiteralPath $installed -PathType Leaf) {
    return
  }
  if (!$FromSource) {
    throw "-WithMoonshine requires an artifact moonshine binary or -FromSource"
  }
  if (!(Get-Command cargo -ErrorAction SilentlyContinue)) {
    throw "-WithMoonshine -FromSource requires cargo"
  }
  Invoke-Step "cargo build moonshine" {
    Push-Location (Join-Path $GnosisRoot "moonshine")
    try {
      cargo build --release
    } finally {
      Pop-Location
    }
    $moonDir = Split-Path -Parent $installed
    New-Item -ItemType Directory -Force -Path $moonDir | Out-Null
    Copy-Item -LiteralPath (Join-Path $GnosisRoot "moonshine\target\release\moonshine.exe") -Destination $installed -Force
  }
}

function Write-CommandShim {
  param([string]$Name)
  Invoke-Step "create $BinDir" { New-Item -ItemType Directory -Force -Path $BinDir | Out-Null }
  $ps1 = Join-Path $BinDir "$Name.ps1"
  $cmd = Join-Path $BinDir "$Name.cmd"
  $body = @"
`$ErrorActionPreference = "Stop"
`$GnosisRoot = "$CommandRoot"
`$CmdName = [System.IO.Path]::GetFileNameWithoutExtension(`$MyInvocation.MyCommand.Name)
`$Node = if (`$env:GNOSIS_NODE) { `$env:GNOSIS_NODE } else { (Get-Command node -ErrorAction SilentlyContinue).Source }
`$NativeMonster = Join-Path `$GnosisRoot "polyglot\target\release\monster.exe"
`$NativeGnexec = Join-Path `$GnosisRoot "polyglot\target\release\gnexec.exe"
`$GnodeCli = Join-Path `$GnosisRoot "bin\gnode.js"
`$GnosisCli = Join-Path `$GnosisRoot "bin\gnosis.js"
`$Moonshine = Join-Path `$GnosisRoot "moonshine\target\release\moonshine.exe"
function Need-Node {
  if (!`$Node) {
    Write-Error "`${CmdName}: node is required for this command path"
    exit 127
  }
}
switch (`$CmdName) {
  "gnexec" {
    if (Test-Path -LiteralPath `$NativeGnexec) { & `$NativeGnexec @args; exit `$LASTEXITCODE }
    if (Test-Path -LiteralPath `$NativeMonster) { & `$NativeMonster @args; exit `$LASTEXITCODE }
    Write-Error "gnexec: native binary not installed; reinstall with an artifact or -FromSource"
    exit 127
  }
  "monster" {
    if (`$args.Count -gt 0 -and `$args[0] -eq "native") {
      if (Test-Path -LiteralPath `$NativeMonster) { & `$NativeMonster @(`$args | Select-Object -Skip 1); exit `$LASTEXITCODE }
      Write-Error "monster: native binary not installed; reinstall with an artifact or -FromSource"
      exit 127
    }
    Need-Node
    `$env:GNODE_TRUST_PREWARMED_BUNDLE = if (`$env:GNODE_TRUST_PREWARMED_BUNDLE) { `$env:GNODE_TRUST_PREWARMED_BUNDLE } else { "1" }
    if (`$args.Count -gt 0 -and `$args[0] -match '\.(ts|tsx|js|sh|gg|gnot|py|go|rs|rb|java|c|cpp|cc|kt|zig|lua|ex|exs)$') {
      & `$Node `$GnodeCli run @args; exit `$LASTEXITCODE
    }
    & `$Node `$GnodeCli @args; exit `$LASTEXITCODE
  }
  "gnode" {
    Need-Node
    `$env:GNODE_TRUST_PREWARMED_BUNDLE = if (`$env:GNODE_TRUST_PREWARMED_BUNDLE) { `$env:GNODE_TRUST_PREWARMED_BUNDLE } else { "1" }
    & `$Node `$GnodeCli @args; exit `$LASTEXITCODE
  }
  "gnosis" {
    Need-Node
    & `$Node `$GnosisCli @args; exit `$LASTEXITCODE
  }
  "gg" {
    Need-Node
    if (`$args.Count -gt 0 -and (`$args[0] -eq "--help" -or `$args[0] -eq "-h" -or `$args[0] -eq "help")) {
      Write-Output "Usage:"
      Write-Output "  gg <file.gg|file.gnot> [args...]   run a GG source through gnode"
      Write-Output "  gg <gnosis-args...>                forward to the gnosis CLI"
      Write-Output ""
      Write-Output "Examples:"
      Write-Output "  gg example.gg"
      Write-Output "  gg lint example.gg"
      exit 0
    }
    if (`$args.Count -gt 0 -and `$args[0] -match '\.(gg|gnot)$') {
      `$env:GNODE_TRUST_PREWARMED_BUNDLE = if (`$env:GNODE_TRUST_PREWARMED_BUNDLE) { `$env:GNODE_TRUST_PREWARMED_BUNDLE } else { "1" }
      & `$Node `$GnodeCli run @args; exit `$LASTEXITCODE
    }
    & `$Node `$GnosisCli @args; exit `$LASTEXITCODE
  }
  "moonshine" {
    if (Test-Path -LiteralPath `$Moonshine) { & `$Moonshine @args; exit `$LASTEXITCODE }
    Write-Error "moonshine: not installed; rerun install.ps1 -WithMoonshine"
    exit 127
  }
}
"@
  Invoke-Step "write $ps1" { Set-Content -LiteralPath $ps1 -Value $body -Encoding UTF8 }
  $cmdBody = "@echo off`r`npowershell -NoProfile -ExecutionPolicy Bypass -File ""%~dp0$Name.ps1"" %*`r`n"
  Invoke-Step "write $cmd" { Set-Content -LiteralPath $cmd -Value $cmdBody -Encoding ASCII }
}

function Update-UserPath {
  if ($NoPath) {
    return
  }
  $current = [Environment]::GetEnvironmentVariable("Path", "User")
  if ($current -and (($current -split ";") -contains $BinDir)) {
    return
  }
  $next = if ($current) { "$BinDir;$current" } else { $BinDir }
  Invoke-Step "add $BinDir to the user PATH" { [Environment]::SetEnvironmentVariable("Path", $next, "User") }
}

$ExpandedArtifactDir = Expand-Artifact
Build-NativeFromSource
if (!(Install-FromArtifactDir $ExpandedArtifactDir)) {
  Install-FromCheckout
}
Build-MoonshineFromSource

foreach ($name in @("gnosis", "gnode", "monster", "gnexec", "gg")) {
  Write-CommandShim $name
}
if ($WithMoonshine) {
  Write-CommandShim "moonshine"
  $moon = Join-Path $BinDir "moonshine.cmd"
  if (!$DryRun -and (Test-Path -LiteralPath $moon) -and !(Test-Path -LiteralPath (Join-Path $HOME ".moonshine.knot"))) {
    & $moon init *> $null
  }
}
Update-UserPath

Write-Host "Gnosis commands installed in $BinDir"
Write-Host "Open a new terminal to pick up PATH changes."
